```python
def range_filter(field, start_date_math=None, end_date_math=None, **kwargs):
    """Create a range filter."""
    def inner(values):
        start, end = values[0].split('--')

        if start_date_math:
            start = '{0}||{1}'.format(start, start_date_math)

        if end_date_math:
            end = '{0}||{1}'.format(end, end_date_math)

        kwargs.update({
            'gte': start,
            'lte': end
        })

        return Range(**{field: params})

    return inner
```

